const config = {
  "previewFeatures": [],
  "clientVersion": "7.4.0",
  "engineVersion": "ab56fe763f921d033a6c195e7ddeb3e255bdbb57",
  "activeProvider": "postgresql",
  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============= USER & AUTH =============\n\nmodel User {\n  id            String    @id @default(cuid())\n  email         String    @unique\n  password      String\n  name          String\n  role          Role      @default(STUDENT)\n  plan          Plan      @default(FREE)\n  avatar        String?\n  phone         String?\n  isActive      Boolean   @default(true)\n  emailVerified Boolean   @default(false)\n  permissions   Json? // Array of permission strings e.g. [\"MANAGE_COURSES\", \"VIEW_FINANCE\"]\n  dob           DateTime?\n  qualification String?\n  college       String?\n\n  // Relations\n  enrollments    Enrollment[]\n  interviews     Interview[]\n  lessonProgress LessonProgress[]\n\n  instituteId String?\n  institute   Institute? @relation(fields: [instituteId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Phase 23: Community & Chat\n  posts         ForumPost[]\n  comments      ForumComment[]\n  conversations Conversation[] @relation(\"UserConversations\")\n  sentMessages  Message[]\n  payments      Payment[]\n  certificates  Certificate[]\n  reviews       Review[]\n\n  // Support\n  tickets            Ticket[]\n  sentTicketMessages TicketMessage[]\n\n  // Phase 25: Career\n  employerProfile EmployerProfile?\n  jobs            Job[] // Jobs posted by this user (if Employer)\n  applications    JobApplication[] // Applications submitted by this user (if Student)\n\n  // Relations: Tasks & Blogs\n  assignedTasks         Task[]                 @relation(\"AssignedTo\")\n  createdTasks          Task[]                 @relation(\"CreatedBy\")\n  blogPosts             BlogPost[]\n  taskComments          TaskComment[]\n  assignmentSubmissions AssignmentSubmission[]\n  lessonComments        LessonComment[]\n\n  // Trainer Portal\n  instructedBatches Batch[]\n  announcements     Announcement[]\n\n  // ATS Relations\n  conductedJobInterviews JobInterview[]\n\n  // RBAC System\n  systemRoleId String?\n  systemRole   SystemRole? @relation(fields: [systemRoleId], references: [id])\n\n  // Library Bookmarks\n  libraryBookmarks LibraryBookmark[]\n}\n\nmodel SystemRole {\n  id          String  @id @default(cuid())\n  name        String  @unique // e.g., \"Junior Admin\", or maps to Role Enum\n  description String?\n  isSystem    Boolean @default(false) // If true, cannot be deleted (matches Enum roles)\n  permissions Json // Array of permission codes [\"MANAGE_USERS\", \"VIEW_FINANCE\"]\n\n  users User[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel SystemPermission {\n  id          String  @id @default(cuid())\n  code        String  @unique // MANAGE_USERS\n  name        String // Manage Users\n  description String?\n  module      String // USERS, COURSES, FINANCE\n\n  createdAt DateTime @default(now())\n}\n\nenum Role {\n  SUPER_ADMIN\n  ADMIN\n  INSTRUCTOR\n  STUDENT\n  STAFF\n  INSTITUTE_ADMIN\n  EMPLOYER\n}\n\nenum Plan {\n  FREE\n  PRO\n  ENTERPRISE\n}\n\n// ============= INSTITUTES =============\n\nmodel Institute {\n  id      String  @id @default(cuid())\n  name    String\n  code    String? @unique\n  logoUrl String?\n  address String?\n  website String?\n  phone   String?\n  email   String?\n\n  // Relations\n  users   User[]\n  courses Course[]\n  batches Batch[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= LMS - COURSES =============\n\nmodel Course {\n  id            String     @id @default(cuid())\n  title         String\n  description   String\n  thumbnail     String?\n  category      String\n  difficulty    Difficulty @default(BEGINNER)\n  duration      Int        @default(0) // in hours\n  price         Decimal    @default(0)\n  discountPrice Decimal    @default(0)\n  courseCode    String?    @unique\n  jobRoles      Json? // Array of job roles e.g. [\"Frontend Dev\", \"UI Engineer\"]\n  bannerUrl     String?\n  averageRating Float      @default(0)\n  instructorId  String\n  isPublished   Boolean    @default(false)\n\n  // Phase 19: Course-Interview Integration\n  hasInterviewPrep Boolean @default(false)\n  interviewPrice   Decimal @default(0)\n  bundlePrice      Decimal @default(0)\n\n  // Phase 24: Course Types\n  courseType   CourseType @default(RECORDED)\n  liveSchedule Json? // { startDate, endDate, sessions: [{date, time, duration, meetingUrl}] }\n  hybridConfig Json? // { livePercentage, recordedModules, liveModules }\n\n  // Phase 24: Deployment Workflow\n  publishStatus        PublishStatus @default(DRAFT)\n  publishedAt          DateTime?\n  reviewNotes          String?\n  submittedForReviewAt DateTime?\n\n  // Relations\n  modules     Module[]\n  enrollments Enrollment[]\n  payments    Payment[]\n  reviews     Review[]\n  liveClasses LiveClass[]\n\n  // Trainer Portal Relations\n  batches       Batch[]\n  announcements Announcement[]\n\n  instituteId String?\n  institute   Institute? @relation(fields: [instituteId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([title, instructorId])\n}\n\n// ============= TRAINER PORTAL: BATCHES =============\n\nmodel Batch {\n  id           String  @id @default(cuid())\n  name         String\n  courseId     String\n  instructorId String\n  instituteId  String?\n\n  startDate   DateTime?\n  endDate     DateTime?\n  description String?\n  maxStudents Int?\n\n  // Relations\n  course        Course         @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  instructor    User           @relation(fields: [instructorId], references: [id], onDelete: Cascade)\n  institute     Institute?     @relation(fields: [instituteId], references: [id])\n  announcements Announcement[]\n  enrollments   Enrollment[] // Students in this batch\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Announcement {\n  id       String @id @default(cuid())\n  title    String\n  content  String @db.Text\n  priority String @default(\"NORMAL\") // NORMAL, URGENT\n\n  courseId     String?\n  batchId      String?\n  instructorId String\n\n  // Relations\n  course     Course? @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  batch      Batch?  @relation(fields: [batchId], references: [id], onDelete: Cascade)\n  instructor User    @relation(fields: [instructorId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel LessonComment {\n  id       String @id @default(cuid())\n  lessonId String\n  userId   String\n  content  String @db.Text\n\n  parentId             String? // For replies\n  isPinned             Boolean @default(false)\n  isInstructorResponse Boolean @default(false)\n\n  // Relations\n  lesson  Lesson          @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n  user    User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  parent  LessonComment?  @relation(\"CommentReplies\", fields: [parentId], references: [id])\n  replies LessonComment[] @relation(\"CommentReplies\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum Difficulty {\n  BEGINNER\n  INTERMEDIATE\n  ADVANCED\n}\n\nenum CourseType {\n  RECORDED // Pre-recorded video lessons\n  LIVE // Scheduled live sessions\n  HYBRID // Mix of live + recorded\n}\n\nenum PublishStatus {\n  DRAFT\n  IN_REVIEW\n  PUBLISHED\n  ARCHIVED\n}\n\nmodel Module {\n  id          String  @id @default(cuid())\n  courseId    String\n  title       String\n  description String?\n  orderIndex  Int\n  isPublished Boolean @default(false)\n\n  // Relations\n  course  Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  lessons Lesson[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([courseId, orderIndex])\n}\n\nenum LessonType {\n  VIDEO\n  TEXT\n  PDF\n  QUIZ\n  ASSIGNMENT\n  LIVE\n}\n\nmodel Lesson {\n  id       String  @id @default(cuid())\n  moduleId String\n  title    String\n  content  String?\n  videoUrl String?\n  duration Int? // in seconds\n  order    Int\n\n  type        LessonType @default(VIDEO)\n  isPublished Boolean    @default(false)\n  isPreview   Boolean    @default(false)\n\n  // Configuration for Quizzes/Assignments\n  settings  Json? // { timeLimit, passingScore, attemptsAllowed, maxFiles }\n  resources Json? // Array of { title, url, type }\n\n  // Relations\n  module                Module                 @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  quizzes               Quiz[]\n  progress              LessonProgress[]\n  comments              LessonComment[]\n  assignmentSubmissions AssignmentSubmission[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Quiz {\n  id            String  @id @default(cuid())\n  lessonId      String\n  question      String\n  options       Json // Array of options\n  correctAnswer String\n  explanation   String?\n\n  // Relations\n  lesson Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\nmodel AssignmentSubmission {\n  id       String @id @default(cuid())\n  lessonId String\n  userId   String\n\n  content String? @db.Text\n  fileUrl String?\n\n  grade    Int?\n  feedback String? @db.Text\n  status   String  @default(\"PENDING\") // PENDING, GRADED, REJECTED\n\n  lesson Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Enrollment {\n  id                 String           @id @default(cuid())\n  userId             String\n  courseId           String\n  progress           Int              @default(0) // percentage\n  status             EnrollmentStatus @default(ACTIVE)\n  hasInterviewAccess Boolean          @default(false) // Phase 19: Bundle Access\n\n  batchId String?\n  // Relations\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course  Course  @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  batch   Batch?  @relation(fields: [batchId], references: [id])\n\n  enrolledAt  DateTime  @default(now())\n  completedAt DateTime?\n\n  @@unique([userId, courseId])\n}\n\nenum EnrollmentStatus {\n  ACTIVE\n  COMPLETED\n  PAUSED\n  CANCELLED\n}\n\nmodel LessonProgress {\n  id             String   @id @default(cuid())\n  userId         String\n  lessonId       String\n  completed      Boolean  @default(false)\n  score          Int? // For Quizzes\n  timeSpent      Int      @default(0) // in seconds\n  lastAccessedAt DateTime @default(now())\n\n  // Relations\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  lesson Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, lessonId])\n}\n\nmodel Review {\n  id       String  @id @default(cuid())\n  userId   String\n  courseId String\n  rating   Int // 1-5\n  comment  String? @db.Text\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= INTERVIEW SYSTEM =============\n\nmodel Interview {\n  id             String     @id @default(cuid())\n  userId         String\n  domain         String // IT, Finance, Marketing, etc.\n  company        String? // Google, Amazon, etc.\n  role           String // SDE, Manager, etc.\n  technology     String? // Added: Primary technology stack\n  jobDescription String?\n  resumeUrl      String?\n  difficulty     Difficulty @default(INTERMEDIATE)\n  panelCount     Int        @default(1)\n  linkedCourseId String? // Phase 19: Link to specific course curriculum\n\n  duration        Int      @default(30) // in minutes\n  selectedAvatars String[] // Avatars selected for this session (Panel)\n\n  status      InterviewStatus @default(SCHEDULED)\n  scheduledAt DateTime?\n  startedAt   DateTime?\n  completedAt DateTime?\n\n  // Relations\n  user       User                 @relation(fields: [userId], references: [id], onDelete: Cascade)\n  questions  InterviewQuestion[]\n  responses  InterviewResponse[]\n  evaluation InterviewEvaluation?\n\n  createdAt DateTime @default(now())\n}\n\nenum InterviewStatus {\n  SCHEDULED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n}\n\nmodel InterviewQuestion {\n  id          String       @id @default(cuid())\n  interviewId String\n  avatarId    String?\n  question    String\n  type        QuestionType\n  order       Int\n\n  // Relations\n  interview Interview          @relation(fields: [interviewId], references: [id], onDelete: Cascade)\n  response  InterviewResponse?\n}\n\nenum QuestionType {\n  TECHNICAL\n  BEHAVIORAL\n  SITUATIONAL\n  HR\n  CODING\n}\n\nmodel InterviewResponse {\n  id          String @id @default(cuid())\n  interviewId String\n  questionId  String @unique\n\n  transcript String?\n  code       String? @db.Text // Candidate code submission\n  videoUrl   String?\n  audioUrl   String?\n  duration   Int? // in seconds\n\n  // Relations\n  interview Interview         @relation(fields: [interviewId], references: [id], onDelete: Cascade)\n  question  InterviewQuestion @relation(fields: [questionId], references: [id], onDelete: Cascade)\n\n  respondedAt DateTime @default(now())\n}\n\nmodel InterviewEvaluation {\n  id          String @id @default(cuid())\n  interviewId String @unique\n\n  overallScore       Int // 0-100\n  technicalScore     Int\n  communicationScore Int\n  confidenceScore    Int\n  starMethodScore    Int\n\n  strengths       Json // Array of strings\n  weaknesses      Json // Array of strings\n  recommendations Json // Array of strings\n\n  aiInsights String?\n\n  // Relations\n  interview Interview @relation(fields: [interviewId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nmodel Avatar {\n  id          String  @id @default(cuid())\n  name        String\n  role        String // Interviewer type\n  personality String // Friendly, Strict, etc.\n  avatarUrl   String\n  gender      Gender? @default(MALE)\n  voiceId     String?\n  provider    String? @default(\"ELEVEN_LABS\")\n\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n}\n\n// ============= ADMIN & AI TRAINING =============\n\nmodel KnowledgeBase {\n  id          String       @id @default(cuid())\n  domain      String // e.g., \"Frontend\", \"Backend\"\n  topic       String // e.g., \"React Hooks\"\n  content     String       @db.Text // The Question\n  answer      String?      @db.Text // The Ideal Answer (for evaluation)\n  difficulty  Difficulty   @default(INTERMEDIATE)\n  type        QuestionType @default(TECHNICAL)\n  codeSnippet String?      @db.Text // For coding questions\n  tags        Json? // Array of strings\n\n  status    KnowledgeStatus @default(PUBLISHED)\n  createdAt DateTime        @default(now())\n  updatedAt DateTime        @updatedAt\n}\n\nenum KnowledgeStatus {\n  DRAFT\n  PUBLISHED\n}\n\nmodel SystemPrompt {\n  id       String  @id @default(cuid())\n  role     String  @unique // e.g., \"Interviewer_Technical\", \"Interviewer_HR\"\n  prompt   String  @db.Text\n  isActive Boolean @default(true)\n\n  updatedAt DateTime @updatedAt\n}\n\n// ============= PAYMENTS =============\n\nmodel Payment {\n  id        String  @id @default(cuid())\n  orderId   String  @unique // Razorpay Order ID\n  paymentId String? @unique // Razorpay Payment ID\n  signature String?\n\n  amount   Float\n  currency String @default(\"INR\")\n  status   String @default(\"PENDING\") // PENDING, SUCCESS, FAILED\n\n  userId   String\n  user     User   @relation(fields: [userId], references: [id])\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= COMMUNITY: FORUM =============\n\nmodel ForumCategory {\n  id          String  @id @default(cuid())\n  name        String  @unique\n  description String?\n  slug        String  @unique\n  icon        String? // URL or Icon name\n\n  posts ForumPost[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel ForumPost {\n  id      String @id @default(cuid())\n  title   String\n  content String @db.Text\n  slug    String @unique\n\n  authorId   String\n  categoryId String\n\n  likes    Int     @default(0)\n  views    Int     @default(0)\n  isPinned Boolean @default(false)\n  isSolved Boolean @default(false)\n\n  // Relations\n  author   User           @relation(fields: [authorId], references: [id], onDelete: Cascade)\n  category ForumCategory  @relation(fields: [categoryId], references: [id])\n  comments ForumComment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel ForumComment {\n  id      String @id @default(cuid())\n  content String @db.Text\n\n  postId   String\n  authorId String\n  parentId String? // For nested replies (optional)\n\n  isSolution Boolean @default(false)\n  likes      Int     @default(0)\n\n  // Relations\n  post   ForumPost @relation(fields: [postId], references: [id], onDelete: Cascade)\n  author User      @relation(fields: [authorId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= COMMUNITY: CHAT =============\n\nmodel Conversation {\n  id      String  @id @default(cuid())\n  name    String? // Group name (optional)\n  isGroup Boolean @default(false)\n\n  // Relations\n  participants User[]    @relation(\"UserConversations\")\n  messages     Message[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Message {\n  id             String @id @default(cuid())\n  conversationId String\n  senderId       String\n  content        String @db.Text\n\n  readBy Json? // Array of userIds who read the message\n\n  // Relations\n  conversation Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  sender       User         @relation(fields: [senderId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\n// ============= CERTIFICATE SYSTEM =============\n\nmodel Certificate {\n  id           String @id @default(cuid())\n  uniqueId     String @unique // Format: CERT-2026-00001\n  userId       String\n  courseId     String\n  enrollmentId String\n\n  // Certificate Details\n  studentName    String\n  courseName     String\n  courseCategory String?\n  issueDate      DateTime  @default(now())\n  expiryDate     DateTime?\n  templateId     String?\n\n  // Signatures\n  signatureUrl   String?\n  signatoryName  String?\n  signatoryTitle String?\n\n  // Verification\n  verificationUrl String?\n  isValid         Boolean @default(true)\n\n  // Grade/Score\n  grade String?\n  score Float?\n\n  // Relations\n  user     User                 @relation(fields: [userId], references: [id], onDelete: Cascade)\n  template CertificateTemplate? @relation(fields: [templateId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel CertificateTemplate {\n  id          String  @id @default(cuid())\n  name        String\n  description String?\n  designUrl   String // Template image URL\n  previewUrl  String? // Thumbnail preview\n  isDefault   Boolean @default(false)\n  isActive    Boolean @default(true)\n\n  // Layout Settings\n  layout Json? // { namePosition, datePosition, signaturePosition, etc }\n\n  // Relations\n  certificates Certificate[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel CertificateSettings {\n  id          String @id @default(cuid())\n  instituteId String @unique @default(\"default\")\n\n  // ID Format Settings\n  prefix          String  @default(\"CERT\")\n  yearInId        Boolean @default(true)\n  sequenceDigits  Int     @default(5)\n  currentSequence Int     @default(0)\n\n  // Signature Settings\n  defaultSignatureUrl   String?\n  defaultSignatoryName  String  @default(\"Director\")\n  defaultSignatoryTitle String  @default(\"Academic Director\")\n\n  // Position Settings (NEW)\n  signaturePosition String  @default(\"bottom-center\") // top-left, top-center, top-right, bottom-left, bottom-center, bottom-right\n  logoPosition      String  @default(\"header\") // header, footer, watermark, top-left, top-right\n  logoSize          String  @default(\"medium\") // small, medium, large\n  signatureSize     String  @default(\"medium\") // small, medium, large\n  borderStyle       String  @default(\"classic\") // classic, modern, minimal, elegant, none\n  backgroundUrl     String? // Custom background image\n\n  // Validity\n  defaultValidityMonths Int? // null = no expiry\n\n  // Branding\n  instituteName    String  @default(\"TechWell Academy\")\n  instituteLogoUrl String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= AI CONFIGURATION =============\n\nmodel AIProvider {\n  id        String  @id @default(cuid())\n  name      String // OpenAI, Gemini, Claude, Anthropic\n  provider  String // OPENAI, GOOGLE, ANTHROPIC, CUSTOM\n  apiKey    String // Encrypted API key\n  model     String // gpt-4, gemini-pro, claude-3, etc.\n  endpoint  String? // Custom endpoint URL\n  isActive  Boolean @default(true)\n  isDefault Boolean @default(false)\n\n  // Usage Tracking\n  usageLimit   Int? // Monthly token/request limit\n  currentUsage Int      @default(0)\n  lastResetAt  DateTime @default(now())\n\n  // Settings\n  temperature Float @default(0.7)\n  maxTokens   Int   @default(2048)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel AIUsageLog {\n  id         String  @id @default(cuid())\n  providerId String\n  userId     String?\n  feature    String // Q&A_GENERATION, INTERVIEW, COURSE_CREATION, etc.\n  tokensUsed Int\n  promptHash String? // For caching\n\n  createdAt DateTime @default(now())\n}\n\n// ============= VIDEO CONFERENCING =============\n\nmodel VideoIntegration {\n  id       String @id @default(cuid())\n  platform String // ZOOM, GOOGLE_MEET, MS_TEAMS\n  name     String // Display name\n\n  // OAuth/API Credentials\n  clientId     String?\n  clientSecret String?\n  apiKey       String?\n  accessToken  String?\n  refreshToken String?\n  tokenExpiry  DateTime?\n\n  // Settings\n  isActive   Boolean @default(false)\n  webhookUrl String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel LiveClass {\n  id          String  @id @default(cuid())\n  courseId    String\n  title       String\n  description String?\n\n  // Meeting Details\n  platform    String // ZOOM, GOOGLE_MEET, MS_TEAMS, CUSTOM\n  meetingLink String?\n  meetingId   String?\n  password    String?\n\n  // Schedule\n  scheduledAt DateTime\n  duration    Int // in minutes\n  timezone    String   @default(\"Asia/Kolkata\")\n\n  // Status\n  status    LiveClassStatus @default(SCHEDULED)\n  startedAt DateTime?\n  endedAt   DateTime?\n\n  // Recording\n  recordingUrl      String?\n  recordingPassword String?\n\n  // Host Info\n  hostId   String?\n  hostName String?\n\n  // Relations\n  course Course @relation(fields: [courseId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum LiveClassStatus {\n  SCHEDULED\n  LIVE\n  COMPLETED\n  CANCELLED\n}\n\n// ============= CRM: LEADS & TASKS =============\n\nmodel Lead {\n  id    String  @id @default(cuid())\n  name  String\n  email String?\n  phone String?\n\n  // Demographics (For Analytics)\n  college       String?\n  qualification String?\n  dob           DateTime?\n  location      String? // City/State\n  gender        String?\n\n  source String // Website, Referral, LinkedIn, Google Ads, etc.\n  status LeadStatus @default(NEW)\n\n  notes      String? @db.Text\n  assignedTo String? // User ID of sales rep\n\n  // Marketing Metadata (Phase 19)\n  platform   String? // META, GOOGLE_GMB, JUSTDIAL, WEBSITE\n  campaignId String?\n  adGroupId  String?\n  adId       String?\n  formId     String?\n\n  // Relations\n  tasks Task[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel MarketingIntegration {\n  id       String @id @default(cuid())\n  platform String // META, GOOGLE_GMB, JUSTDIAL\n  name     String\n\n  // Auth\n  accessToken  String? // Page Access Token for Meta\n  refreshToken String?\n  accountId    String? // Ad Account ID or Location ID\n  pageId       String? // Facebook Page ID\n\n  // Settings\n  isActive      Boolean @default(false)\n  webhookSecret String? // Verify incoming webhooks\n\n  lastSyncAt DateTime?\n  createdAt  DateTime  @default(now())\n  updatedAt  DateTime  @updatedAt\n}\n\nmodel EmailIntegration {\n  id       String  @id @default(cuid())\n  provider String // SMTP, EMAILJS, SENDGRID, AWS_SES\n  name     String? // \"Marketing SMTP\" or \"Transactional EmailJS\"\n\n  // SMTP Fields\n  host      String?\n  port      Int?\n  user      String?\n  pass      String?\n  secure    Boolean @default(true)\n  fromEmail String?\n\n  // API Fields (EmailJS / SendGrid)\n  serviceId  String? // EmailJS Service ID\n  templateId String? // EmailJS Template ID (Default)\n  publicKey  String? // EmailJS Public Key\n  privateKey String? // EmailJS Private Key\n  apiKey     String? // SendGrid API Key\n\n  isActive  Boolean  @default(false)\n  updatedAt DateTime @updatedAt\n}\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  INTERESTED\n  QUALIFIED\n  CONVERTED\n  LOST\n}\n\nmodel Task {\n  id          String  @id @default(cuid())\n  title       String\n  description String?\n\n  status   TaskStatus @default(PENDING)\n  priority Priority   @default(MEDIUM)\n  dueDate  DateTime?\n\n  assignedTo String?\n  assignee   User?   @relation(\"AssignedTo\", fields: [assignedTo], references: [id])\n  createdBy  String?\n  creator    User?   @relation(\"CreatedBy\", fields: [createdBy], references: [id])\n\n  // Relations\n  leadId   String?\n  lead     Lead?         @relation(fields: [leadId], references: [id])\n  comments TaskComment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel TaskComment {\n  id      String @id @default(cuid())\n  content String\n\n  taskId String\n  task   Task   @relation(fields: [taskId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel BlogPost {\n  id         String  @id @default(cuid())\n  title      String\n  slug       String  @unique\n  content    String  @db.Text\n  summary    String? @db.Text\n  coverImage String?\n\n  status BlogStatus @default(DRAFT)\n  tags   Json? // Array of strings\n\n  authorId String\n  author   User   @relation(fields: [authorId], references: [id])\n\n  publishedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n}\n\nenum BlogStatus {\n  DRAFT\n  IN_REVIEW\n  PUBLISHED\n  ARCHIVED\n}\n\nenum TaskStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETED\n  OVERDUE\n}\n\nenum Priority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\n// ============= SUPPORT SYSTEM =============\n\nmodel Ticket {\n  id          String         @id @default(cuid())\n  subject     String\n  description String\n  status      TicketStatus   @default(OPEN)\n  priority    TicketPriority @default(MEDIUM)\n  category    TicketCategory @default(GENERAL)\n\n  // Relations\n  userId        String\n  user          User    @relation(fields: [userId], references: [id])\n  assignedTo    String? // ID of admin/staff assigned\n  internalNotes String? @db.Text\n\n  messages TicketMessage[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel TicketMessage {\n  id            String  @id @default(cuid())\n  message       String\n  attachmentUrl String?\n  isStaffReply  Boolean @default(false)\n\n  ticketId String\n  ticket   Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  user      User?    @relation(fields: [userId], references: [id])\n  userId    String?\n}\n\nenum TicketStatus {\n  OPEN\n  IN_PROGRESS\n  RESOLVED\n  CLOSED\n}\n\nenum TicketPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum TicketCategory {\n  GENERAL\n  TECHNICAL\n  BILLING\n  COURSE_CONTENT\n  FEATURE_REQUEST\n}\n\n// ============= PAYMENT CONFIGURATION =============\n\nmodel PaymentConfig {\n  id String @id @default(cuid())\n\n  // Razorpay\n  razorpayKeyId     String?\n  razorpayKeySecret String?\n\n  // Stripe\n  stripePublishableKey String?\n  stripeSecretKey      String?\n\n  // Settings\n  activeGateway Gateway @default(RAZORPAY)\n  currency      String  @default(\"INR\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum Gateway {\n  RAZORPAY\n  STRIPE\n  NONE\n}\n\nmodel Expense {\n  id          String   @id @default(cuid())\n  title       String\n  amount      Float\n  category    String // Salary, Rent, Softwares, etc.\n  description String?\n  date        DateTime @default(now())\n\n  createdBy String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= SYSTEM SETTINGS =============\n\nmodel SystemSettings {\n  id String @id @default(\"default\") // Singleton pattern\n\n  // General Branding\n  platformName String  @default(\"TechWell Academy\")\n  supportEmail String  @default(\"support@techwell.com\")\n  logoUrl      String?\n  faviconUrl   String?\n\n  // Theme\n  primaryColor String @default(\"#2563eb\") // blue-600\n\n  // Maintenance\n  isMaintenanceMode Boolean @default(false)\n\n  // Contact Info\n  address String?\n  phone   String?\n\n  updatedAt DateTime @updatedAt\n}\n\n// ============= CAREER SYSTEM =============\n\nmodel EmployerProfile {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  companyName String\n  website     String?\n  description String? @db.Text\n  logo        String?\n  location    String?\n  industry    String?\n  companySize String?\n\n  status            EmployerStatus @default(PENDING)\n  documentsVerified Boolean        @default(false)\n  verificationNotes String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Job {\n  id           String  @id @default(cuid())\n  title        String\n  description  String  @db.Text\n  requirements String? @db.Text\n  location     String\n  type         JobType @default(FULL_TIME)\n  experience   String? // e.g. \"0-1 years\"\n  salary       String? // e.g. \"5-8 LPA\"\n\n  // New Fields\n  skills        String? // Comma separated\n  clientName    String? // For consultancies\n  shift         String? // Day, Night, Rotational\n  domain        String? // IT, Finance, etc.\n  qualification String?\n\n  // Relations\n  employerId String\n  employer   User   @relation(fields: [employerId], references: [id])\n\n  applications JobApplication[]\n\n  status      JobStatus @default(DRAFT)\n  publishedAt DateTime?\n  expiresAt   DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel JobApplication {\n  id String @id @default(cuid())\n\n  jobId String\n  job   Job    @relation(fields: [jobId], references: [id])\n\n  // Applicant Info\n  applicantId String? // Optional for external candidates\n  applicant   User?   @relation(fields: [applicantId], references: [id])\n\n  // Source Tracking (CRITICAL)\n  source CandidateSource @default(INTERNAL)\n\n  // External Candidate Details\n  externalName  String?\n  externalEmail String?\n  externalPhone String?\n\n  resumeUrl   String?\n  coverLetter String? @db.Text\n\n  // ATS & Scoring\n  // Hidden field for storing parsed resume text for searching/scoring\n  resumeParsedText String? @db.Text\n  atsScore         Float   @default(0) // Match percentage (0-100)\n\n  status        ApplicationStatus @default(APPLIED)\n  statusHistory Json? // Array of { status, updatedBy, timestamp, notes }\n\n  // Relations\n  interviews JobInterview[]\n  emailLogs  EmailLog[]\n  auditLogs  AuditLog[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Unique constraint only applies if applicantId is present\n  // For external, we might want unique on (jobId, externalEmail)\n  @@unique([jobId, applicantId])\n}\n\nenum EmployerStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum JobType {\n  FULL_TIME\n  PART_TIME\n  INTERNSHIP\n  CONTRACT\n  FREELANCE\n}\n\nenum CandidateSource {\n  INTERNAL // Techwell Students\n  EXTERNAL // Outside Applicants\n}\n\nenum JobStatus {\n  DRAFT\n  OPEN\n  PUBLISHED\n  PAUSED\n  CLOSED\n  ARCHIVED\n}\n\nenum ApplicationStatus {\n  APPLIED\n  VIEWED\n  SCREENED\n  SHORTLISTED\n  INTERVIEW_PENDING\n  INTERVIEW_SCHEDULED\n  INTERVIEWED\n  INTERVIEW_COMPLETED\n  SELECTED\n  APPOINTED // HIRED\n  HIRED\n  REJECTED\n  REVIEWING\n}\n\n// ============= ATS & RECRUITMENT SYSTEM (NEW) =============\n\nmodel JobInterview {\n  id String @id @default(cuid())\n\n  applicationId String\n  application   JobApplication @relation(fields: [applicationId], references: [id], onDelete: Cascade)\n\n  // Round Details\n  roundName String // e.g. \"Technical Round 1\", \"HR Round\"\n  roundType InterviewRoundType @default(TECHNICAL)\n\n  // Schedule\n  scheduledAt DateTime\n  duration    Int      @default(30) // minutes\n  meetingLink String?\n  location    String? // For offline\n\n  // Interviewer\n  interviewerId String\n  interviewer   User   @relation(fields: [interviewerId], references: [id])\n\n  // Outcome\n  status   InterviewStatus  @default(SCHEDULED)\n  feedback String?          @db.Text\n  score    Int? // 1-10 or 1-100\n  result   InterviewResult? // PASS/FAIL\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel EmailLog {\n  id String @id @default(cuid())\n\n  // Context\n  jobId         String?\n  applicationId String?\n  application   JobApplication? @relation(fields: [applicationId], references: [id])\n\n  recipientEmail String\n  recipientName  String?\n\n  templateName String // e.g. \"APPLICATION_RECEIVED\"\n  subject      String\n  body         String @db.Text\n\n  status EmailStatus @default(SENT)\n  sentAt DateTime    @default(now())\n  error  String?\n\n  triggeredBy String? // User ID who triggered this\n}\n\nmodel AuditLog {\n  id         String  @id @default(cuid())\n  entityType String // JOB, APPLICATION, INTERVIEW, USER, SYSTEM\n  entityId   String?\n  action     String // CREATE, UPDATE, DELETE, STATUS_CHANGE, LOGIN, APPROVE\n\n  // Request Context\n  method    String? // POST, PUT, DELETE\n  path      String? // /api/users/profile\n  ipAddress String?\n  userAgent String?\n\n  // Data Changes\n  oldValue Json?\n  newValue Json?\n\n  // For Application Context\n  applicationId String?\n  application   JobApplication? @relation(fields: [applicationId], references: [id])\n\n  performedBy String\n  details     Json? // { oldStatus: \"APPLIED\", newStatus: \"SHORTLISTED\", notes: \"...\" }\n\n  timestamp DateTime @default(now())\n}\n\nmodel SavedFilter {\n  id     String @id @default(cuid())\n  name   String\n  userId String // Recruiter ID\n  page   String // \"CANDIDATES\" or \"JOBS\"\n\n  config Json // { source: [\"INTERNAL\"], minExperience: 2 }\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nenum InterviewRoundType {\n  SCREENING\n  TECHNICAL\n  MANAGERIAL\n  HR\n  FINAL\n  OTHER\n}\n\nenum InterviewResult {\n  PASSED\n  FAILED\n  ON_HOLD\n}\n\nenum EmailStatus {\n  SENT\n  FAILED\n  QUEUED\n}\n\n// ============= PROJECTS MARKETPLACE =============\nmodel Project {\n  id            String  @id @default(cuid())\n  title         String\n  description   String  @db.Text\n  price         String\n  originalPrice String?\n  image         String?\n  techStack     Json // Array of strings\n  category      String\n\n  // New Fields for Detailed Reports\n  features    Json? // Array of key features\n  capex       String? // Capital Expenditure (e.g. \"5 Lakhs\")\n  roi         String? // Return on Investment\n  projectType String  @default(\"ACADEMIC\") // ACADEMIC, INDUSTRIAL, BUSINESS_DPR, NGO, GOVT_SCHEME\n  demoLink    String?\n  reportLink  String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= SKILLCAST (EXPERT INTERVIEWS) =============\nmodel Skillcast {\n  id          String  @id @default(cuid())\n  title       String\n  description String  @db.Text\n  videoUrl    String\n  expertName  String\n  designation String\n  company     String\n  linkedinUrl String?\n  experience  String?\n  thumbnail   String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= CMS: GALLERY =============\nmodel GalleryImage {\n  id       String  @id @default(cuid())\n  url      String  @db.Text\n  caption  String?\n  order    Int     @default(0)\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ============= AI BEHAVIOR INTELLIGENCE =============\n\nmodel AIBehaviorEvent {\n  id        String  @id @default(cuid())\n  sessionId String // Browser session ID\n  userId    String? // If logged in\n\n  eventType String // PAGE_VIEW, SCROLL, CLICK, TIME_ON_PAGE, CTA_CLICK\n  eventData Json // { page, scrollDepth, ctaId, duration, element, etc }\n\n  userAgent String?\n  ipAddress String?\n\n  createdAt DateTime @default(now())\n\n  @@index([sessionId])\n  @@index([userId])\n  @@index([eventType])\n  @@index([createdAt])\n}\n\nmodel UserIntent {\n  id        String  @id @default(cuid())\n  sessionId String  @unique\n  userId    String?\n\n  primaryIntent String // INTERVIEW_FOCUSED, COURSE_FOCUSED, JOB_FOCUSED, BROWSING\n\n  interviewScore Float @default(0)\n  courseScore    Float @default(0)\n  jobScore       Float @default(0)\n\n  confidence    Float   @default(0)\n  popupShown    Boolean @default(false)\n  popupResponse String? // What user selected in popup\n\n  metadata Json? // Additional tracking data\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([sessionId])\n  @@index([userId])\n  @@index([primaryIntent])\n}\n\n// ============= LIBRARY MANAGEMENT =============\n\nmodel LibraryCategory {\n  id          String  @id @default(cuid())\n  name        String  @unique\n  description String?\n  icon        String?\n  order       Int     @default(0)\n\n  domains LibraryDomain[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel LibraryDomain {\n  id          String          @id @default(cuid())\n  name        String\n  description String?\n  categoryId  String\n  category    LibraryCategory @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  resources LibraryResource[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([categoryId, name])\n  @@index([categoryId])\n}\n\nmodel LibraryResource {\n  id          String  @id @default(cuid())\n  title       String\n  description String?\n  type        String // PDF or QA\n\n  // For PDF type\n  fileUrl  String?\n  fileName String?\n  fileSize Int?\n\n  // For Q&A type\n  content Json? // { questions: [{q, a}] }\n\n  domainId String\n  domain   LibraryDomain @relation(fields: [domainId], references: [id], onDelete: Cascade)\n\n  views     Int @default(0)\n  downloads Int @default(0)\n\n  createdBy String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  bookmarks LibraryBookmark[]\n\n  @@index([domainId])\n  @@index([type])\n  @@index([createdAt])\n}\n\nmodel LibraryBookmark {\n  id         String   @id @default(cuid())\n  userId     String\n  resourceId String\n  createdAt  DateTime @default(now())\n\n  user     User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  resource LibraryResource @relation(fields: [resourceId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, resourceId])\n}\n"
}

